A segment tree answers 'sum of range [l..r]' in O(log n) AND allows point updates in O(log n). Each node 
stores the sum (or min, or max) of a segment of the array. 
class SegTree: 
 def __init__(self, arr): 
 self.n = len(arr) 
 self.tree = [0] * (4 * self.n) 
 self.build(arr, 1, 0, self.n - 1) 

 def build(self, arr, node, l, r): 
 if l == r: 
 self.tree[node] = arr[l]; return 
 mid = (l + r) // 2 
 self.build(arr, 2*node, l, mid) 
 self.build(arr, 2*node+1, mid+1, r) 
 self.tree[node] = self.tree[2*node] + self.tree[2*node+1] 

 def query(self, node, l, r, ql, qr): 
 if qr < l or r < ql: return 0 
 if ql <= l and r <= qr: return self.tree[node] 
 mid = (l + r) // 2 
 return (self.query(2*node, l, mid, ql, qr) + 
 self.query(2*node+1, mid+1, r, ql, qr)) 

 def update(self, node, l, r, idx, val): 
 if l == r: 
 self.tree[node] = val; return 
 mid = (l + r) // 2 
 if idx <= mid: self.update(2*node, l, mid, idx, val) 
 else: self.update(2*node+1, mid+1, r, idx, val) 
 self.tree[node] = self.tree[2*node] + self.tree[2*node+1] 
